using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Helper estático para a "pausa física" do jogo (Etapa 8): Time.timeScale = 0
/// para tudo, à espera de Resume(). Guarda o timeScale anterior para o
/// restaurar correctamente (ex: se o jogo já estivesse em câmara lenta por
/// outro motivo). A sequência de ações do próprio evento que pausou continua a
/// correr em tempo real porque as ações de espera usam
/// NpcActionUtil.Wait/WaitForSecondsRealtime quando Time.timeScale == 0 — ver
/// Action_Wait, Action_PauseGame, Action_ResumeGame.
/// </summary>
public static class GamePauseUtil
{
    private static float _savedTimeScale = 1f;
    private static bool _paused;

    public static bool IsPaused => _paused;

    public static void Pause()
    {
        if (_paused) return;

        _savedTimeScale = Time.timeScale;
        Time.timeScale = 0f;
        _paused = true;
    }

    public static void Resume()
    {
        if (!_paused) return;

        Time.timeScale = _savedTimeScale;
        _paused = false;
    }
}

/// <summary>
/// Helper estático para "pausar NPCs em movimento" (Etapa 8): suspende
/// temporariamente o NpcMovement de qualquer NPC que esteja actualmente em
/// FollowPlayer/FleePlayer/Patrol (os "modos activos" — tratados aqui como
/// "inimigos"/NPCs em movimento autónomo), opcionalmente só dentro de um raio
/// a partir do player. Guarda quais foram pausados para Resume() restaurar
/// exactamente esses, mesmo que outro NPC mude de modo entretanto.
/// </summary>
public static class NpcPauseUtil
{
    private static readonly List<NpcMovement> _paused = new List<NpcMovement>();

    /// <summary>true se há NPCs actualmente pausados por esta acção.</summary>
    public static bool HasPaused => _paused.Count > 0;

    /// <summary>
    /// Pausa todos os NPCs em FollowPlayer/FleePlayer/Patrol. Se "radius" for
    /// maior que 0 e "npc" tiver um Player atribuído, só pausa os que estiverem
    /// a essa distância (ou menos) do player; "radius" <= 0 = sem limite
    /// (todos os NPCs da cena).
    /// </summary>
    public static void PauseNearbyNpcs(NpcController npc, float radius)
    {
        Transform player = npc != null ? npc.Player : null;

        var allNpcs = Object.FindObjectsOfType<NpcController>();

        foreach (var other in allNpcs)
        {
            var movement = other != null ? other.Movement : null;
            if (movement == null || movement.IsMovementPaused) continue;

            var mode = movement.DefaultMode;
            if (mode != NpcMovementMode.FollowPlayer && mode != NpcMovementMode.FleePlayer && mode != NpcMovementMode.Patrol)
                continue;

            if (radius > 0f && player != null)
            {
                float dist = Vector2.Distance(player.position, other.transform.position);
                if (dist > radius) continue;
            }

            if (movement.Pause())
                _paused.Add(movement);
        }
    }

    /// <summary>Retoma todos os NPCs pausados por PauseNearbyNpcs e limpa a lista.</summary>
    public static void ResumePausedNpcs()
    {
        foreach (var movement in _paused)
        {
            if (movement != null) movement.Resume();
        }

        _paused.Clear();
    }
}
